import React, { useState } from 'react';
import { NavLink } from 'react-router-dom';
import './Sidebar.css';

const navItems = [
  { to: '/',           icon: '⊞',  label: 'Dashboard'    },
  { to: '/tasks',      icon: '📋', label: 'Bài tập'       },
  { to: '/todo',       icon: '✅', label: 'To-do List'    },
  { to: '/documents',  icon: '📁', label: 'Tài liệu'      },
  { to: '/notes',      icon: '📝', label: 'Ghi chép'      },
];

export default function Sidebar({ isOpen, onClose }) {
  return (
    <>
      {/* Overlay for mobile */}
      {isOpen && <div className="sidebar-overlay" onClick={onClose} />}

      <aside className={`sidebar ${isOpen ? 'sidebar--open' : ''}`}>
        {/* Logo */}
        <div className="sidebar-logo">
          <div className="sidebar-logo-icon">🦀</div>
          <div className="sidebar-logo-text">
            <span className="sidebar-logo-name">TDTapp</span>
            <span className="sidebar-logo-sub">Open Claw</span>
          </div>
          {/* Close button mobile */}
          <button className="sidebar-close-btn" onClick={onClose}>✕</button>
        </div>

        <div className="sidebar-divider" />

        {/* Nav */}
        <nav className="sidebar-nav">
          <p className="sidebar-section-label">MENU CHÍNH</p>
          {navItems.map(item => (
            <NavLink
              key={item.to}
              to={item.to}
              end={item.to === '/'}
              onClick={onClose}
              className={({ isActive }) =>
                `sidebar-link ${isActive ? 'sidebar-link--active' : ''}`
              }
            >
              <span className="sidebar-link-icon">{item.icon}</span>
              <span className="sidebar-link-label">{item.label}</span>
            </NavLink>
          ))}
        </nav>

        {/* Footer */}
        <div className="sidebar-footer">
          <div className="sidebar-user">
            <div className="sidebar-user-avatar">SV</div>
            <div className="sidebar-user-info">
              <span className="sidebar-user-name">Sinh viên TDT</span>
              <span className="sidebar-user-role">TSMC</span>
            </div>
          </div>
        </div>
      </aside>
    </>
  );
}
